template.script:

document.addEventListener('DOMContentLoaded', function() {
    const carousel = document.getElementById('heroCarousel');
    const carouselTrack = document.getElementById('carouselTrack');
    const carouselIndicators = document.getElementById('carouselIndicators');
    const prevBtn = document.getElementById('carouselPrev');
    const nextBtn = document.getElementById('carouselNext');
    const heroTitle = document.getElementById('heroTitle');
    const heroDescription = document.getElementById('heroDescription');

    // ...existing code...
    let slides = [];
    let currentIndex = 0;
    let autoScrollInterval;

    // Fetch property media data from backend
    async function fetchPropertyMedia() {
        try {
            // Fetch the first property with media
            const response = await fetch('/web/dataset/call_kw/cruise.property/search_read', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                },
                body: JSON.stringify({
                    jsonrpc: '2.0',
                    method: 'call',
                    params: {
                        model: 'cruise.property',
                        method: 'search_read',
                        args: [[], ['id', 'name', 'description', 'media_ids']],
                        kwargs: {limit: 1}
                    }
                })
            });

            const data = await response.json();

            if (data.result && data.result.length > 0) {
                const property = data.result[0];
                console.log('Property fetched:', property);

                // If property has media, fetch media details
                if (property.media_ids && property.media_ids.length > 0) {
                    const mediaResponse = await fetch('/web/dataset/call_kw/media/search_read', {
                        method: 'POST',
                        headers: {
                            'Content-Type': 'application/json',
                        },
                        body: JSON.stringify({
                            jsonrpc: '2.0',
                            method: 'call',
                            params: {
                                model: 'media',
                                method: 'search_read',
                                args: [
                                    [['id', 'in', property.media_ids]],
                                    ['id', 'name', 'image', 'description']
                                ],
                                kwargs: {}
                            }
                        })
                    });

                    const mediaData = await mediaResponse.json();
                    console.log('Media fetched:', mediaData);

                    if (mediaData.result && mediaData.result.length > 0) {
                        // Build slides from media data with IDs
                        slides = mediaData.result.map((media, index) => ({
                            id: media.id,
                            image: media.image ? `data:image/jpg;base64,${media.image}` : '/cleopatra_cruise/static/src/img/carousel-1.jpg',
                            // title: media.name || `Media ${index + 1}`,
                            description: media.description || property.description || 'Luxury Cruise Experience'
                        }));

                        console.log('Slides created:', slides);
                        initCarousel();
                        return;
                    }
                }
            }

            // Fallback: Use default placeholder slides if no media found
            console.log('No property media found, using defaults');
            initCarouselWithDefaults();
        } catch (error) {
            console.error('Error fetching property media:', error);
            // Fallback to defaults on error
            initCarouselWithDefaults();
        }
    }

    // Initialize with default placeholder slides (fallback)
    function initCarouselWithDefaults() {
        slides = [
            {
                id: 0,
                image: '/cleopatra_cruise/static/src/img/carousel-1.jpg',
                title: 'Luxury Nile Cruises',
                description: 'Experience the magic of Egypt\'s most iconic river'
            },
            {
                id: 1,
                image: '/cleopatra_cruise/static/src/img/carousel-2.jpg',
                title: 'Premium Cabins',
                description: 'Elegantly designed suites with breathtaking river views'
            },
            {
                id: 2,
                image: '/cleopatra_cruise/static/src/img/carousel-3.jpg',
                title: 'Ancient Wonders',
                description: 'Discover temples, tombs, and archaeological marvels'
            }
        ];
        initCarousel();
    }

    // Initialize carousel
    function initCarousel() {
        // Clear existing slides first
        carouselTrack.innerHTML = '';
        carouselIndicators.innerHTML = '';

        // Create slides with media IDs
        slides.forEach((slide, index) => {
            const slideEl = document.createElement('div');
            slideEl.className = 'hero-carousel-slide';
            slideEl.setAttribute('data-media-id', slide.id);
            slideEl.innerHTML = `
                <img src="${slide.image}" alt="${slide.title}" class="hero-carousel-image"/>
            `;
            carouselTrack.appendChild(slideEl);

            // Create indicator with media ID
            const indicator = document.createElement('button');
            indicator.className = 'hero-indicator' + (index === 0 ? ' active' : '');
            indicator.setAttribute('data-slide', index);
            indicator.setAttribute('data-media-id', slide.id);
            indicator.setAttribute('aria-label', `Go to slide ${index + 1}`);
            indicator.onclick = () => goToSlide(index);
            carouselIndicators.appendChild(indicator);
        });

        startAutoScroll();
    }

    // Update carousel position
    function updateCarousel() {
        const offset = -currentIndex * 100;
        carouselTrack.style.transform = `translateX(${offset}%)`;

        // Update indicators
        document.querySelectorAll('.hero-indicator').forEach((ind, i) => {
            ind.classList.toggle('active', i === currentIndex);
        });

        // Update text content
        if (slides[currentIndex]) {
            heroTitle.textContent = slides[currentIndex].title;
            heroDescription.textContent = slides[currentIndex].description;
        }
    }

    // Go to specific slide
    function goToSlide(index) {
        currentIndex = index % slides.length;
        updateCarousel();
        resetAutoScroll();
    }

    // Next slide
    function nextSlide() {
        currentIndex = (currentIndex + 1) % slides.length;
        updateCarousel();
        resetAutoScroll();
    }

    // Previous slide
    function prevSlide() {
        currentIndex = (currentIndex - 1 + slides.length) % slides.length;
        updateCarousel();
        resetAutoScroll();
    }

    // Auto-scroll every 5 seconds
    function startAutoScroll() {
        autoScrollInterval = setInterval(nextSlide, 5000);
    }

    // Reset auto-scroll timer
    function resetAutoScroll() {
        clearInterval(autoScrollInterval);
        startAutoScroll();
    }

    // Event listeners
    prevBtn.addEventListener('click', prevSlide);
    nextBtn.addEventListener('click', nextSlide);
    // ...existing code...
    // Pause auto-scroll on hover
    carousel.addEventListener('mouseenter', () => clearInterval(autoScrollInterval));
    carousel.addEventListener('mouseleave', startAutoScroll);

    // Initialize carousel with dynamic property media
    fetchPropertyMedia();
});

// Navbar shrink on scroll
window.addEventListener('scroll', function() {
    const navbar = document.getElementById('mainNavbar');
    if (window.scrollY > 100) {
        navbar.classList.add('shrink');
    } else {
        navbar.classList.remove('shrink');
    }
});
